form:Form.form:Scripts:
		function internalAddHorario()
{
	var hor;
	if (Ctrl("arrHorarios").CountRow()>0)
	{	
		var MyROWHOR=Ctrl("arrHorarios").GetRow(Ctrl("arrHorarios").CountRow()-1);
		hor = MyROWHOR.GetAttr("oi_horario");
	}
	else	
		hor = MyDAT["HOR"].def.id;

	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	var horario;				
	horario = nSQL.GetOBJ(Ctrl("main").getResource("QRY_HOR_CT"), "<PARAM oi_horario=\""+hor+"\"/>");

	if(horario.l_cambio_turno == "0")
	{
		var horct;				
		horct = nSQL.GetOBJ(Ctrl("main").getResource("QRY_CT"), "");	
		hor = horct.oi_horario;
	}


	var newDate=new Date();
	MyROW=Ctrl("arrHorarios").AddRow();
	MyROW.SetAttr("id"            ,"#"+datetime2str(newDate));	
	MyROW.SetAttr("oi_horario"    ,hor);	
	MyROW.SetAttr("oi_escuadra"   ,"");
	MyROW.SetAttr("f_fechaInicio" ,"");
	MyROW.SetAttr("f_fechaFin"    ,"");
	MyROW.SetAttr("o_horariopers" ,"");

	Ctrl("oi_horario"   ).SetXValue(MyROW.GetAttr("oi_horario"   ));	
	Ctrl("oi_escuadra"  ).SetXValue(MyROW.GetAttr("oi_escuadra"  ));
	Ctrl("f_fechaInicio").SetXValue(MyROW.GetAttr("f_fechaInicio"));
	Ctrl("f_fechaFin"   ).SetXValue(xxx_adddays(MyROW.GetAttr("f_fechaFin"),-1));
	Ctrl("o_horariopers").SetXValue(MyROW.GetAttr("o_horariopers"));

	SetData("HOR", MyROW.GetAttr("oi_horario"));

	MyHORSel=MyROW;
	StartEdit();
	New=true;

	ChangeHorario();
} 

function OnClickHorario(obj, dte, value)
{
}

function StartEditCT()
{
	CtrlEnabled("f_fechaInicio", false);
	CtrlEnabled("f_fechaFin", false);

	StartEdit();
}

function LoadReferences()
{	
	var myDate=Ctrl('ESPERANZA_PERIODO').GetXValue() + '01';	
	var PARAM = "<DATO oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+ "\" f_desde=\""+myDate+"\"/>";	
	//Referencias
	aux=Obtener("TUR", "TURNOS", PARAM);        DrawReference(aux, "REFERENCIA_TUR");
	aux=Obtener("LIC", "TIPOS_DE_HORA", PARAM); DrawReference(aux, "REFERENCIA_LIC");
	aux=Obtener("HOR", "HORARIOS", PARAM);      DrawReference(aux, "REFERENCIA_HOR");
	//aux=Obtener("CTU", "CAMBIOTURNO", PARAM);   DrawReference(aux, "REFERENCIA_CAMBIO");

	//Cargo el Rango
	NomadTimeout("OnChangePeriodo(); RefreshControls();", 100, "Cargando la Esperanza...");
}

function RefreshControls()
{
	//Desactivo los Controles de Cambio
	if (MyHORSel==null)
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	} else 
	if (Edit)
	{
		CtrlEnabled("DATA"  , true );
		CtrlEnabled("ADD"   , false);
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , false);
		CtrlEnabled("ACCEPT", true );
		CtrlEnabled("CANCEL", true );
	} else
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , true );
		CtrlEnabled("DELETE", true );
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	}

	//if(MyDAT["CTU"].def == null)
		//CtrlEnabled("ADD"   , false);
}

function SetData(NAME, KEY)
{
	if (Ctrl("main").GetMode()!="EDIT") return;

	MyDAT[NAME].sel=KEY;     	
	if (MyDAT[NAME].cont!="")
	 DrawReference(MyDAT[NAME], MyDAT[NAME].cont);

	if ((NAME=="HOR") && (Edit))
	{		
		Ctrl("oi_horario").SetXValue(MyDAT[NAME].arr[KEY].id);		
		ChangeHorario();		
	}	
}

function DrawReference(myOBJ, ContainerName)
{                         
	var HTMLoutput="", key;
	var TrgObj=document.getElementById(ContainerName);

	myOBJ.cont=ContainerName;
	HTMLoutput+="<TABLE style='width:99%;height:100%cursor:default;font-family:arial;font-size:10px;font-weight:bold;color:#000000;background-color:#F0F0D0;' >";
	for (key in myOBJ.arr)
	{
		HTMLoutput+="<TR style='height:20px;"+(key==myOBJ.sel?"background-color:#F0F0A0;":"")+"' >"
		           +"<TD style='border-bottom:1px dotted #808080;width:30px;font-size:1px;' ><div style='padding:0px;height:12px;border-left:2px solid #"+myOBJ.arr[key].color+";border-right:2px solid #"+myOBJ.arr[key].color+";' ><div style='position:relative;top:4px;height:4px;width:100%;background-color:#"+myOBJ.arr[key].color+";' ></div></div></TD>"
		           +"<TD style='border-bottom:1px dotted #808080;' >"+myOBJ.arr[key].label+"</TD>"
		           +"</TR>";
	}
	HTMLoutput+="</TABLE>";

	TrgObj.innerHTML=HTMLoutput;
}
